import React, { useState } from 'react';
import { Target, AlertCircle } from 'lucide-react';

const BudgetSettings = () => {
  const [budgets, setBudgets] = useState({
    food: 500,
    transport: 300,
    entertainment: 200,
    shopping: 400
  });

  const [actualSpending, setActualSpending] = useState({
    food: 320,
    transport: 280,
    entertainment: 150,
    shopping: 350
  });

  const budgetData = [
    { 
      category: 'Food', 
      budget: budgets.food, 
      spent: actualSpending.food, 
      color: '#3b82f6',
      percentage: ((actualSpending.food / budgets.food) * 100).toFixed(1)
    },
    { 
      category: 'Transport', 
      budget: budgets.transport, 
      spent: actualSpending.transport, 
      color: '#8b5cf6',
      percentage: ((actualSpending.transport / budgets.transport) * 100).toFixed(1)
    },
    { 
      category: 'Entertainment', 
      budget: budgets.entertainment, 
      spent: actualSpending.entertainment, 
      color: '#ec4899',
      percentage: ((actualSpending.entertainment / budgets.entertainment) * 100).toFixed(1)
    },
    { 
      category: 'Shopping', 
      budget: budgets.shopping, 
      spent: actualSpending.shopping, 
      color: '#f59e0b',
      percentage: ((actualSpending.shopping / budgets.shopping) * 100).toFixed(1)
    }
  ];

  return (
    <div className="budget-settings">
      <div className="page-header">
        <h1><Target size={24} /> Budget Settings</h1>
      </div>
      
      <div className="budget-grid-cards">
        {budgetData.map((item, index) => (
          <div 
            key={item.category} 
            className="budget-card-colorful"
            style={{ '--card-color': item.color }}
          >
            <div className="budget-card-header">
              <h3 className="budget-category-name">{item.category}</h3>
              <div className="budget-amount-main">${item.budget}</div>
            </div>
            
            <div className="budget-card-details">
              <div className="spent-amount">Spent: ${item.spent}</div>
              <div className="percentage-badge">{item.percentage}%</div>
            </div>

            {parseFloat(item.percentage) > 90 && (
              <div className="over-budget-warning">
                <AlertCircle size={14} />
                Over budget!
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default BudgetSettings;
